import { Injectable, OnDestroy } from '@angular/core';
import { PuiWorkerRuntime } from './worker-runtime';
import type {
  PuiWorkerDatasetItem,
  PuiWorkerRequest,
  PuiWorkerResponse,
} from './worker.types';
import { computeDatasetFingerprint } from './dataset.utils';

interface PendingRequest {
  readonly resolve: (response: PuiWorkerResponse) => void;
  readonly reject: (error: Error) => void;
}

/**
 * Manages Premium UI worker lifecycle, routing, cancellation, and fallback.
 * Workers are opt-in — callers pass useWorker to delegate heavy computation.
 */
@Injectable({ providedIn: 'root' })
export class PuiWorkerManager implements OnDestroy {
  private worker: Worker | null = null;
  private workerSupported = false;
  private workerInitialized = false;
  private requestCounter = 0;
  private latestRequestId = 0;

  private readonly fallbackRuntime = new PuiWorkerRuntime();
  private readonly pending = new Map<number, PendingRequest>();
  private readonly datasetFingerprints = new Map<string, string>();

  ngOnDestroy(): void {
    this.terminateWorker();
  }

  isWorkerSupported(): boolean {
    return this.workerSupported;
  }

  async ensureDataset(
    datasetId: string,
    items: readonly PuiWorkerDatasetItem[],
    useWorker: boolean
  ): Promise<void> {
    const fingerprint = computeDatasetFingerprint(items);

    if (this.datasetFingerprints.get(datasetId) === fingerprint) {
      return;
    }

    await this.dispatch(
      {
        type: 'init-dataset',
        payload: { datasetId, items, fingerprint },
      },
      useWorker
    );

    this.datasetFingerprints.set(datasetId, fingerprint);
  }

  async dispatch(
    request: Omit<PuiWorkerRequest, 'requestId'>,
    useWorker: boolean
  ): Promise<PuiWorkerResponse> {
    const requestId = ++this.requestCounter;
    this.latestRequestId = requestId;
    const fullRequest: PuiWorkerRequest = { ...request, requestId };

    if (useWorker && this.tryInitializeWorker()) {
      return this.dispatchToWorker(fullRequest);
    }

    return Promise.resolve(this.fallbackRuntime.handle(fullRequest));
  }

  cancelLatest(): void {
    if (this.latestRequestId > 0) {
      this.cancel(this.latestRequestId);
    }
  }

  cancel(requestId: number): void {
    this.fallbackRuntime.cancelRequest(requestId);

    if (this.worker && this.workerSupported) {
      const cancelRequest: PuiWorkerRequest = {
        requestId,
        type: 'cancel',
        payload: { requestId },
      };
      this.worker.postMessage(cancelRequest);
    }

    const pending = this.pending.get(requestId);
    if (pending) {
      pending.resolve({
        requestId,
        datasetId: '',
        indices: [],
        cancelled: true,
      });
      this.pending.delete(requestId);
    }
  }

  private tryInitializeWorker(): boolean {
    if (this.workerInitialized) {
      return this.workerSupported;
    }

    this.workerInitialized = true;

    if (typeof Worker === 'undefined') {
      this.workerSupported = false;
      return false;
    }

    try {
      this.worker = new Worker(new URL('./data.worker', import.meta.url), { type: 'module' });
      this.worker.addEventListener('message', (event: MessageEvent<PuiWorkerResponse>) => {
        this.handleWorkerMessage(event.data);
      });
      this.worker.addEventListener('error', () => {
        this.workerSupported = false;
        this.rejectAllPending(new Error('Worker crashed'));
        this.terminateWorker();
      });
      this.workerSupported = true;
      return true;
    } catch {
      this.workerSupported = false;
      this.worker = null;
      return false;
    }
  }

  private dispatchToWorker(request: PuiWorkerRequest): Promise<PuiWorkerResponse> {
    if (!this.worker) {
      return Promise.resolve(this.fallbackRuntime.handle(request));
    }

    return new Promise<PuiWorkerResponse>((resolve, reject) => {
      this.pending.set(request.requestId, { resolve, reject });
      this.worker!.postMessage(request);
    });
  }

  private handleWorkerMessage(response: PuiWorkerResponse): void {
    const pending = this.pending.get(response.requestId);
    if (!pending) {
      return;
    }

    this.pending.delete(response.requestId);

    if ('error' in response) {
      pending.reject(new Error(response.error));
      return;
    }

    pending.resolve(response);
  }

  private rejectAllPending(error: Error): void {
    for (const [requestId, pending] of this.pending.entries()) {
      pending.reject(error);
      this.pending.delete(requestId);
    }
  }

  private terminateWorker(): void {
    this.worker?.terminate();
    this.worker = null;
    this.workerSupported = false;
    this.workerInitialized = false;
    this.rejectAllPending(new Error('Worker terminated'));
  }
}

import { ChangeDetectionStrategy, Component, computed, inject, signal } from '@angular/core';
import { toSignal } from '@angular/core/rxjs-interop';
import { ActivatedRoute, RouterLink, RouterLinkActive } from '@angular/router';
import { map } from 'rxjs';
import { PuiButtonComponent } from '../../../../premium-ui/components/button';
import {
  PuiCardActionsComponent,
  PuiCardBadgeComponent,
  PuiCardComponent,
  PuiCardContentComponent,
  PuiCardFooterComponent,
  PuiCardHeaderComponent,
  PuiCardImageComponent,
  PuiCardSubtitleComponent,
  PuiCardTitleComponent,
} from '../../../../premium-ui/components/card';
import type { PuiCardSize, PuiCardVariant } from '../../../../premium-ui/components/card';
import { PuiCheckboxComponent } from '../../../../premium-ui/components/checkbox';
import { PuiSelectComponent } from '../../../../premium-ui/components/select';
import type { PuiSelectValue } from '../../../../premium-ui/components/select';
import type { PuiDocCodeTab, PuiDocApiRow, PuiDocA11yItem, PuiDocsTab } from '../../docs.types';
import {
  PuiDocApiTableComponent,
  PuiDocA11yListComponent,
  PuiDocExampleComponent,
  buildHtmlTsTabs,
  buildPlaygroundTsExample,
  buildThemeTabs,
  toSelectOptions,
} from '../../shared';
import { useDocsPageSeo } from '../../seo/use-docs-page-seo';

type PuiDocsCardTab =
  | 'overview'
  | 'examples'
  | 'layouts'
  | 'api'
  | 'accessibility'
  | 'theming'
  | 'playground';

interface PuiApiRow {
  readonly name: string;
  readonly type: string;
  readonly defaultValue: string;
  readonly description: string;
}

const PRODUCT_IMAGE =
  'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=800&h=600&fit=crop';

const CARD_IMPORTS = [
  { name: 'PuiCardComponent', path: '@premium-ui/components/card' },
  { name: 'PuiCardHeaderComponent', path: '@premium-ui/components/card' },
  { name: 'PuiCardTitleComponent', path: '@premium-ui/components/card' },
  { name: 'PuiCardSubtitleComponent', path: '@premium-ui/components/card' },
  { name: 'PuiCardContentComponent', path: '@premium-ui/components/card' },
  { name: 'PuiCardFooterComponent', path: '@premium-ui/components/card' },
  { name: 'PuiCardActionsComponent', path: '@premium-ui/components/card' },
  { name: 'PuiButtonComponent', path: '@premium-ui/components/button' },
] as const;

const CARD_MEDIA_IMPORTS = [
  ...CARD_IMPORTS,
  { name: 'PuiCardImageComponent', path: '@premium-ui/components/card' },
] as const;

const CARD_PRICING_IMPORTS = [
  ...CARD_IMPORTS,
  { name: 'PuiCardBadgeComponent', path: '@premium-ui/components/card' },
] as const;

@Component({
  selector: 'app-card-docs',
  imports: [
    PuiCardComponent,
    PuiCardHeaderComponent,
    PuiCardTitleComponent,
    PuiCardSubtitleComponent,
    PuiCardContentComponent,
    PuiCardFooterComponent,
    PuiCardActionsComponent,
    PuiCardImageComponent,
    PuiCardBadgeComponent,
    PuiButtonComponent,
    PuiSelectComponent,
    PuiCheckboxComponent,
    PuiDocApiTableComponent,
    PuiDocA11yListComponent,
    PuiDocExampleComponent,
    RouterLink,
    RouterLinkActive,
  ],
  templateUrl: './card-docs.component.html',
  styleUrl: './card-docs.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class CardDocsComponent {
  private readonly route = inject(ActivatedRoute);

  private readonly routeTab = toSignal(
    this.route.paramMap.pipe(map((params) => params.get('tab') ?? 'overview')),
    { initialValue: 'overview' }
  );

  protected readonly currentTab = computed<PuiDocsCardTab>(() => {
    const tab = this.routeTab();
    return this.isDocsTab(tab) ? tab : 'overview';
  });

  protected readonly tabs: readonly PuiDocsTab[] = [
    { label: 'Overview', route: ['/docs/components/card/overview'] },
    { label: 'Examples', route: ['/docs/components/card/examples'] },
    { label: 'Layouts', route: ['/docs/components/card/layouts'] },
    { label: 'API Guide', route: ['/docs/components/card/api'] },
    { label: 'Accessibility', route: ['/docs/components/card/accessibility'] },
    { label: 'Theming', route: ['/docs/components/card/theming'] },
    { label: 'Playground', route: ['/docs/components/card/playground'] },
  ];

  constructor() {
    useDocsPageSeo({ slug: 'card', tab: this.currentTab });
  }

  protected readonly variants: readonly PuiCardVariant[] = [
    'default',
    'outlined',
    'elevated',
    'ghost',
    'glass',
    'gradient',
  ];

  protected readonly variantDescriptions: Record<PuiCardVariant, string> = {
    default: 'Soft gradient surface with layered ambient shadows and inner highlight.',
    outlined: 'Semi-transparent surface with subtle border and restrained depth.',
    elevated: 'High elevation with deeper ambient shadow stack on hover.',
    ghost: 'Borderless transparent surface for nested or minimal layouts.',
    glass: 'Frosted glass with blur, layered highlights, and soft ambient depth.',
    gradient: 'Primary-tinted gradient with spotlight overlay for featured content.',
  };

  protected readonly sizes: readonly PuiCardSize[] = ['sm', 'md', 'lg'];
  protected readonly variantOptions = toSelectOptions(this.variants);
  protected readonly sizeOptions = toSelectOptions(this.sizes);
  protected readonly productImage = PRODUCT_IMAGE;

  protected readonly htmlExample = `<pui-card hoverable>
  <pui-card-header>
    <pui-card-title>Revenue</pui-card-title>
    <pui-card-subtitle>Monthly analytics</pui-card-subtitle>
  </pui-card-header>
  <pui-card-content>Your content here</pui-card-content>
  <pui-card-footer>
    <pui-card-actions>
      <pui-button size="sm" variant="ghost">View</pui-button>
    </pui-card-actions>
  </pui-card-footer>
</pui-card>`;

  protected readonly pricingExample = `<pui-card variant="gradient" highlighted hoverable>
  <pui-card-header split>
    <pui-card-title>Pro</pui-card-title>
    <pui-card-badge variant="primary" pill>Popular</pui-card-badge>
  </pui-card-header>
  <pui-card-content>$49 / month</pui-card-content>
  <pui-card-footer>
    <pui-button>Choose plan</pui-button>
  </pui-card-footer>
</pui-card>`;

  protected readonly productExample = `<pui-card hoverable imageZoom>
  <pui-card-image src="..." alt="Product" zoomOnHover aspect="square" />
  <pui-card-title>Product name</pui-card-title>
  <pui-card-footer>
    <pui-button size="sm">Add to cart</pui-button>
  </pui-card-footer>
</pui-card>`;

  protected readonly overviewExampleTabs = buildHtmlTsTabs(this.htmlExample, {
    selector: 'app-card-overview',
    componentClass: 'CardOverviewExampleComponent',
    imports: CARD_IMPORTS,
    templateUrl: './card-overview.component.html',
  });

  protected readonly pricingExampleTabs = buildHtmlTsTabs(this.pricingExample, {
    selector: 'app-card-pricing',
    componentClass: 'CardPricingExampleComponent',
    imports: CARD_PRICING_IMPORTS,
    templateUrl: './card-pricing.component.html',
  });

  protected readonly productExampleTabs = buildHtmlTsTabs(this.productExample, {
    selector: 'app-card-product',
    componentClass: 'CardProductExampleComponent',
    imports: CARD_MEDIA_IMPORTS,
    templateUrl: './card-product.component.html',
  });

  protected readonly themeTabs = buildThemeTabs(`:host {
  --pui-card-bg: var(--pui-color-surface);
  --pui-card-border: var(--pui-color-border);
  --pui-card-shadow: var(--pui-shadow-lg);
  --pui-card-hover-shadow: var(--pui-shadow-xl);
  --pui-card-radius: var(--pui-radius-xl);
  --pui-card-padding: var(--pui-space-lg);
}`);

  protected readonly cardApiRows: readonly PuiApiRow[] = [
    { name: 'variant', type: 'PuiCardVariant', defaultValue: 'default', description: 'Visual style: default, outlined, elevated, ghost, glass, gradient.' },
    { name: 'size', type: 'PuiCardSize', defaultValue: 'md', description: 'Padding scale: sm, md, lg.' },
    { name: 'layout', type: 'vertical | horizontal', defaultValue: 'vertical', description: 'Stack content vertically or place media beside content.' },
    { name: 'hoverable', type: 'boolean', defaultValue: 'false', description: 'Enables subtle lift and shadow on hover.' },
    { name: 'interactive', type: 'boolean', defaultValue: 'false', description: 'Makes the card clickable with keyboard support.' },
    { name: 'loading', type: 'boolean', defaultValue: 'false', description: 'Shows skeleton placeholder state.' },
    { name: 'highlighted', type: 'boolean', defaultValue: 'false', description: 'Premium emphasis ring for pricing or featured content.' },
    { name: 'imageZoom', type: 'boolean', defaultValue: 'false', description: 'Enables image zoom on hover for nested pui-card-image.' },
    { name: 'disabled', type: 'boolean', defaultValue: 'false', description: 'Disables interaction for interactive cards.' },
  ];

  protected readonly primitiveApiRows: readonly PuiApiRow[] = [
    { name: 'pui-card-header', type: 'component', defaultValue: '-', description: 'Header region with optional split layout for title + actions.' },
    { name: 'pui-card-title', type: 'component', defaultValue: '-', description: 'Semantic card heading.' },
    { name: 'pui-card-subtitle', type: 'component', defaultValue: '-', description: 'Supporting header text.' },
    { name: 'pui-card-content', type: 'component', defaultValue: '-', description: 'Main body content area.' },
    { name: 'pui-card-footer', type: 'component', defaultValue: '-', description: 'Footer actions and metadata.' },
    { name: 'pui-card-actions', type: 'component', defaultValue: '-', description: 'Inline action cluster, typically in header/footer.' },
    { name: 'pui-card-image', type: 'component', defaultValue: '-', description: 'Media with aspect ratio, overlay, gradient, and zoom.' },
    { name: 'pui-card-badge', type: 'component', defaultValue: '-', description: 'Status badge with semantic variants.' },
  ];

  protected readonly a11yItems: readonly PuiDocA11yItem[] = [
    { title: 'Card title', code: 'pui-card-title', description: 'Renders semantic heading text for the card region.' },
    { title: 'Interactive cards', code: 'role="button"', description: 'Clickable cards expose button semantics, keyboard activation, and focus-visible styles.' },
    { title: 'Card images', code: 'alt', description: 'pui-card-image requires meaningful alt text for non-decorative media.' },
    { title: 'Loading state', code: 'aria-busy', description: 'Loading cards set aria-busy on the host while content is pending.' },
  ];

  protected readonly playgroundVariant = signal<PuiCardVariant>('elevated');
  protected readonly playgroundSize = signal<PuiCardSize>('md');
  protected readonly playgroundHoverable = signal(true);
  protected readonly playgroundHighlighted = signal(false);
  protected readonly playgroundLoading = signal(false);

  protected readonly playgroundCode = computed(() => {
    const attrs = [
      this.playgroundHoverable() ? ' hoverable' : '',
      this.playgroundHighlighted() ? ' highlighted' : '',
      this.playgroundLoading() ? ' loading' : '',
      this.playgroundVariant() !== 'default' ? ` variant="${this.playgroundVariant()}"` : '',
      this.playgroundSize() !== 'md' ? ` size="${this.playgroundSize()}"` : '',
    ].join('');

    return `<pui-card${attrs}>
  <pui-card-title>Preview</pui-card-title>
  <pui-card-content>Composable premium card</pui-card-content>
</pui-card>`;
  });

  protected readonly playgroundExampleTabs = computed((): readonly PuiDocCodeTab[] => [
    { id: 'html', label: 'HTML', code: this.playgroundCode(), language: 'html', filename: 'playground.component.html' },
    { id: 'ts', label: 'TypeScript', code: this.playgroundTsExample(), language: 'typescript', filename: 'playground.component.ts' },
  ]);

  protected readonly playgroundTsExample = computed(() =>
    buildPlaygroundTsExample({
      componentClass: 'CardPlaygroundComponent',
      imports: [
        { name: 'PuiCardComponent', path: '@premium-ui/components/card' },
        { name: 'PuiCardTitleComponent', path: '@premium-ui/components/card' },
        { name: 'PuiCardContentComponent', path: '@premium-ui/components/card' },
      ],
      members: [
        `protected readonly variant = signal('${this.playgroundVariant()}' as const);`,
        `protected readonly size = signal('${this.playgroundSize()}' as const);`,
        `protected readonly hoverable = signal(${this.playgroundHoverable()});`,
        `protected readonly highlighted = signal(${this.playgroundHighlighted()});`,
        `protected readonly loading = signal(${this.playgroundLoading()});`,
      ],
    })
  );

  protected setPlaygroundVariant(value: PuiSelectValue | null): void {
    if (typeof value === 'string') {
      this.playgroundVariant.set(value as PuiCardVariant);
    }
  }

  protected setPlaygroundSize(value: PuiSelectValue | null): void {
    if (typeof value === 'string') {
      this.playgroundSize.set(value as PuiCardSize);
    }
  }

  private isDocsTab(tab: string): tab is PuiDocsCardTab {
    return ['overview', 'examples', 'layouts', 'api', 'accessibility', 'theming', 'playground'].includes(tab);
  }
}

import { JsonPipe } from '@angular/common';
import { ChangeDetectionStrategy, Component, computed, inject, signal } from '@angular/core';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { toSignal } from '@angular/core/rxjs-interop';
import { ActivatedRoute, RouterLink, RouterLinkActive } from '@angular/router';
import { map } from 'rxjs';
import {
  PuiCheckboxComponent,
  PuiCheckboxDescriptionComponent,
  PuiCheckboxGroupComponent,
  PuiCheckboxLabelComponent,
} from '../../../../premium-ui/components/checkbox';
import type { PuiCheckboxVariant } from '../../../../premium-ui/components/checkbox';
import { PuiSelectComponent } from '../../../../premium-ui/components/select';
import type { PuiSelectValue } from '../../../../premium-ui/components/select';
import type { PuiDocCodeTab, PuiDocApiRow, PuiDocA11yItem, PuiDocKeyboardShortcut, PuiDocsTab } from '../../docs.types';
import type { PuiSize } from '../../../../premium-ui/types/common.types';
import {
  PuiDocApiTableComponent,
  PuiDocA11yListComponent,
  PuiDocExampleComponent,
  PuiDocKeyboardShortcutsComponent,
  buildHtmlTsTabs,
  buildPlaygroundTsExample,
  buildThemeTabs,
  toSelectOptions,
} from '../../shared';
import { useDocsPageSeo } from '../../seo/use-docs-page-seo';

type PuiDocsCheckboxTab =
  | 'overview'
  | 'examples'
  | 'api'
  | 'accessibility'
  | 'forms'
  | 'signal-forms'
  | 'theming'
  | 'playground';

interface PuiApiRow extends PuiDocApiRow {}

@Component({
  selector: 'app-checkbox-docs',
  imports: [
    PuiCheckboxComponent,
    PuiCheckboxGroupComponent,
    PuiCheckboxLabelComponent,
    PuiCheckboxDescriptionComponent,
    PuiSelectComponent,
    PuiDocApiTableComponent,
    PuiDocA11yListComponent,
    PuiDocExampleComponent,
    PuiDocKeyboardShortcutsComponent,
    ReactiveFormsModule,
    JsonPipe,
    RouterLink,
    RouterLinkActive,
  ],
  templateUrl: './checkbox-docs.component.html',
  styleUrl: './checkbox-docs.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class CheckboxDocsComponent {
  private readonly route = inject(ActivatedRoute);
  private readonly fb = inject(FormBuilder);

  private readonly routeTab = toSignal(
    this.route.paramMap.pipe(map((params) => params.get('tab') ?? 'overview')),
    { initialValue: 'overview' }
  );

  protected readonly currentTab = computed<PuiDocsCheckboxTab>(() => {
    const tab = this.routeTab();
    return this.isDocsTab(tab) ? tab : 'overview';
  });

  protected readonly tabs: readonly PuiDocsTab[] = [
    { label: 'Overview', route: ['/docs/components/checkbox/overview'] },
    { label: 'Examples', route: ['/docs/components/checkbox/examples'] },
    { label: 'API Guide', route: ['/docs/components/checkbox/api'] },
    { label: 'Accessibility', route: ['/docs/components/checkbox/accessibility'] },
    { label: 'Forms', route: ['/docs/components/checkbox/forms'] },
    { label: 'Signal Forms', route: ['/docs/components/checkbox/signal-forms'] },
    { label: 'Theming', route: ['/docs/components/checkbox/theming'] },
    { label: 'Playground', route: ['/docs/components/checkbox/playground'] },
  ];

  constructor() {
    useDocsPageSeo({ slug: 'checkbox', tab: this.currentTab });
  }

  protected readonly variants: readonly PuiCheckboxVariant[] = [
    'default',
    'filled',
    'soft',
    'minimal',
    'card',
  ];
  protected readonly sizes: readonly PuiSize[] = ['sm', 'md', 'lg'];
  protected readonly variantOptions = toSelectOptions(this.variants);
  protected readonly sizeOptions = toSelectOptions(this.sizes);

  protected readonly selectedFrameworks = signal<string[]>(['angular']);
  protected readonly signalChecked = signal(false);

  protected readonly reactiveForm = this.fb.nonNullable.group({
    terms: [false, Validators.requiredTrue],
    marketing: [true],
  });

  protected readonly basicExample = `<pui-checkbox>Accept terms and conditions</pui-checkbox>`;

  protected readonly statesExampleCode = `<pui-checkbox [checked]="true">Checked</pui-checkbox>
<pui-checkbox>Unchecked</pui-checkbox>
<pui-checkbox [indeterminate]="true">Indeterminate</pui-checkbox>`;

  protected readonly controlledExample = `<pui-checkbox
  [checked]="selected()"
  (checkedChange)="onChecked($event)"
>
  Accept terms
</pui-checkbox>`;

  protected readonly groupExample = `<pui-checkbox-group [(value)]="selected">
  <pui-checkbox value="angular">Angular</pui-checkbox>
  <pui-checkbox value="react">React</pui-checkbox>
</pui-checkbox-group>`;

  protected readonly reactiveExample = `<form [formGroup]="form">
  <pui-checkbox formControlName="terms">
    Accept terms
  </pui-checkbox>
</form>`;

  protected readonly cardExample = `<pui-checkbox variant="card" value="pro">
  <pui-checkbox-label>Pro plan</pui-checkbox-label>
  <pui-checkbox-description>Advanced features</pui-checkbox-description>
</pui-checkbox>`;

  protected readonly basicExampleTabs = buildHtmlTsTabs(this.basicExample, {
    selector: 'app-checkbox-basic',
    componentClass: 'CheckboxBasicExampleComponent',
    imports: [{ name: 'PuiCheckboxComponent', path: '@premium-ui/components/checkbox' }],
    templateUrl: './checkbox-basic.component.html',
  });

  protected readonly statesExampleTabs = buildHtmlTsTabs(this.statesExampleCode, {
    selector: 'app-checkbox-states',
    componentClass: 'CheckboxStatesExampleComponent',
    imports: [{ name: 'PuiCheckboxComponent', path: '@premium-ui/components/checkbox' }],
    templateUrl: './checkbox-states.component.html',
  });

  protected readonly groupExampleTabs = buildHtmlTsTabs(this.groupExample, {
    selector: 'app-checkbox-group-example',
    componentClass: 'CheckboxGroupExampleComponent',
    imports: [
      { name: 'PuiCheckboxComponent', path: '@premium-ui/components/checkbox' },
      { name: 'PuiCheckboxGroupComponent', path: '@premium-ui/components/checkbox' },
    ],
    templateUrl: './checkbox-group.component.html',
    usesSignal: true,
    members: ["protected readonly selected = signal<string[]>(['angular']);"],
  });

  protected readonly cardExampleTabs = buildHtmlTsTabs(this.cardExample, {
    selector: 'app-checkbox-card',
    componentClass: 'CheckboxCardExampleComponent',
    imports: [
      { name: 'PuiCheckboxComponent', path: '@premium-ui/components/checkbox' },
      { name: 'PuiCheckboxLabelComponent', path: '@premium-ui/components/checkbox' },
      { name: 'PuiCheckboxDescriptionComponent', path: '@premium-ui/components/checkbox' },
    ],
    templateUrl: './checkbox-card.component.html',
  });

  protected readonly reactiveExampleTabs = buildHtmlTsTabs(this.reactiveExample, {
    selector: 'app-checkbox-reactive',
    componentClass: 'CheckboxReactiveExampleComponent',
    imports: [
      { name: 'PuiCheckboxComponent', path: '@premium-ui/components/checkbox' },
      { name: 'ReactiveFormsModule', path: '@angular/forms' },
    ],
    injects: [{ name: 'FormBuilder', path: '@angular/forms' }],
    templateUrl: './checkbox-reactive.component.html',
    members: [
      'private readonly fb = inject(FormBuilder);',
      'protected readonly form = this.fb.group({ terms: [false] });',
    ],
  });

  protected readonly controlledExampleTabs = buildHtmlTsTabs(this.controlledExample, {
    selector: 'app-checkbox-controlled',
    componentClass: 'CheckboxControlledExampleComponent',
    imports: [{ name: 'PuiCheckboxComponent', path: '@premium-ui/components/checkbox' }],
    templateUrl: './checkbox-controlled.component.html',
