import { ChangeDetectionStrategy, Component, computed, inject, signal } from '@angular/core';
import { RouterLink, RouterLinkActive } from '@angular/router';
import type { PuiDocsNavGroup } from '../docs.types';
import { PuiDocsSearchService } from '../services/docs-search.service';

@Component({
  selector: 'app-docs-sidebar',
  imports: [RouterLink, RouterLinkActive],
  templateUrl: './docs-sidebar.component.html',
  styleUrl: './docs-sidebar.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class DocsSidebarComponent {
  private readonly searchService = inject(PuiDocsSearchService);

  protected readonly query = this.searchService.query;
  protected readonly collapsedGroups = signal<readonly string[]>([
    'foundations',
    'feedback',
    'navigation',
    'overlays',
    'layout',
    'utilities'
  ]);

  private readonly groups: readonly PuiDocsNavGroup[] = [
    {
      id: 'foundations',
      label: 'Foundations',
      items: [
        { label: 'Colors', route: ['/docs/foundations/colors'] },
        { label: 'Typography', route: ['/docs/foundations/typography'] },
        { label: 'Spacing', route: ['/docs/foundations/spacing'] }
      ]
    },
    {
      id: 'forms',
      label: 'Forms',
      items: [
        { label: 'Button', route: ['/docs/components/button/overview'], badge: 'Ready' },
        { label: 'Input', route: ['/docs/components/input/overview'], badge: 'Ready' },
        { label: 'Select', route: ['/docs/components/select/overview'], badge: 'Ready' },
        { label: 'Checkbox', route: ['/docs/components/checkbox/overview'], badge: 'Ready' },
        { label: 'Radio', route: ['/docs/components/radio/overview'], badge: 'Ready' },
        { label: 'Switch', route: ['/docs/components/switch/overview'], badge: 'Ready' },
        { label: 'Toggle', route: ['/docs/components/toggle/overview'], badge: 'Ready' }
      ]
    },
    {
      id: 'feedback',
      label: 'Feedback',
      items: [
        { label: 'Alert', route: ['/docs/components/alert'] },
        { label: 'Toast', route: ['/docs/components/toast/overview'], badge: 'Ready' },
        { label: 'Progress', route: ['/docs/components/progress'] }
      ]
    },
    {
      id: 'navigation',
      label: 'Navigation',
      items: [
        { label: 'Tabs', route: ['/docs/components/tabs/overview'], badge: 'Ready' },
        { label: 'Breadcrumb', route: ['/docs/components/breadcrumb'] }
      ]
    },
    {
      id: 'overlays',
      label: 'Overlays',
      items: [
        { label: 'Modal', route: ['/docs/components/modal'] },
        { label: 'Tooltip', route: ['/docs/components/tooltip'] }
      ]
    },
    {
      id: 'data-display',
      label: 'Data Display',
      items: [
        { label: 'Card', route: ['/docs/components/card/overview'], badge: 'Ready' },
        { label: 'Badge', route: ['/docs/components/badge'] },
        { label: 'Table', route: ['/docs/components/table'] }
      ]
    },
    {
      id: 'layout',
      label: 'Layout',
      items: [
        { label: 'Container', route: ['/docs/components/container'] },
        { label: 'Stack', route: ['/docs/components/stack'] }
      ]
    },
    {
      id: 'utilities',
      label: 'Utilities',
      items: [
        { label: 'Visually Hidden', route: ['/docs/components/visually-hidden'] },
        { label: 'Portal', route: ['/docs/components/portal'] }
      ]
    }
  ];

  protected readonly filteredGroups = computed(() => {
    const query = this.query().trim().toLowerCase();

    if (!query) {
      return this.groups;
    }

    return this.groups
      .map((group) => ({
        ...group,
        items: group.items.filter((item) => item.label.toLowerCase().includes(query))
      }))
      .filter((group) => group.items.length > 0);
  });

  protected updateQuery(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.searchService.setQuery(input.value);
  }

  protected isCollapsed(groupId: string): boolean {
    return this.collapsedGroups().includes(groupId);
  }

  protected toggleGroup(groupId: string): void {
    this.collapsedGroups.update((groups) =>
      groups.includes(groupId) ? groups.filter((id) => id !== groupId) : [...groups, groupId]
    );
  }
}

import { DOCUMENT, isPlatformBrowser } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  DestroyRef,
  PLATFORM_ID,
  afterNextRender,
  effect,
  inject,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { NavigationEnd, Router } from '@angular/router';
import { filter } from 'rxjs';
import { PuiDocsTocService } from '../services/docs-toc.service';

@Component({
  selector: 'app-docs-toc',
  templateUrl: './docs-toc.component.html',
  styleUrl: './docs-toc.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class DocsTocComponent {
  protected readonly tocService = inject(PuiDocsTocService);
  protected readonly activeId = signal<string | null>(null);
  protected readonly mobileOpen = signal(false);

  private readonly document = inject(DOCUMENT);
  private readonly platformId = inject(PLATFORM_ID);
  private readonly router = inject(Router);
  private readonly destroyRef = inject(DestroyRef);
  private observer: IntersectionObserver | null = null;

  constructor() {
    afterNextRender(() => this.setupObserver());

    effect(() => {
      this.tocService.revision();
      this.setupObserver();
    });

    this.router.events
      .pipe(
        filter((event) => event instanceof NavigationEnd),
        takeUntilDestroyed(this.destroyRef)
      )
      .subscribe(() => {
        this.activeId.set(null);
        this.setupObserver();
      });

    this.destroyRef.onDestroy(() => this.observer?.disconnect());
  }

  protected isActive(id: string): boolean {
    return this.activeId() === id;
  }

  protected toggleMobile(): void {
    this.mobileOpen.update((open) => !open);
  }

  protected navigateToSection(event: Event, id: string): void {
    event.preventDefault();
    const target = this.document.getElementById(id);
    if (!target) {
      return;
    }

    target.scrollIntoView({ behavior: 'smooth', block: 'start' });

    if (isPlatformBrowser(this.platformId)) {
      this.document.defaultView?.history.replaceState(null, '', `#${id}`);
    }

    this.activeId.set(id);
  }

  private setupObserver(): void {
    this.observer?.disconnect();
    this.observer = null;

    if (!isPlatformBrowser(this.platformId) || typeof IntersectionObserver === 'undefined') {
      return;
    }

    const items = this.tocService.items();
    const sections = items
      .map((item) => this.document.getElementById(item.id))
      .filter((section): section is HTMLElement => section !== null);

    if (sections.length === 0) {
      this.activeId.set(null);
      return;
    }

    this.activeId.set(sections[0].id);

    this.observer = new IntersectionObserver(
      (entries) => {
        const visible = entries
          .filter((entry) => entry.isIntersecting)
          .sort((a, b) => a.boundingClientRect.top - b.boundingClientRect.top);

        if (visible[0]?.target.id) {
          this.activeId.set(visible[0].target.id);
          this.scrollActiveLinkIntoView(visible[0].target.id);
        }
      },
      {
        rootMargin: '-96px 0px -62% 0px',
        threshold: [0, 0.15, 0.4, 0.75],
      }
    );

    sections.forEach((section) => this.observer?.observe(section));
  }

  private scrollActiveLinkIntoView(id: string): void {
    const link = this.document.querySelector<HTMLElement>(`.pui-toc__link[data-toc-id="${id}"]`);
    link?.scrollIntoView({ block: 'nearest', inline: 'nearest' });
  }
}

