        <pui-radio value="daily">Daily</pui-radio>
        <pui-radio value="weekly">Weekly</pui-radio>
        <pui-radio value="monthly">Monthly</pui-radio>
      </pui-radio-group>
      <p class="pui-radio-showcase-meta">Selected: {{ filter() }}</p>
    `,
