    template: `
      <pui-radio-group [(value)]="notifications" ariaLabel="Notifications">
        <pui-radio value="all">All notifications</pui-radio>
        <pui-radio value="mentions">Mentions only</pui-radio>
        <pui-radio value="none">None</pui-radio>
      </pui-radio-group>
    `,
  }),
