          <pui-radio-description>Instant transfer</pui-radio-description>
        </pui-radio>
        <pui-radio variant="card" value="apple">
          <pui-radio-label>Apple Pay</pui-radio-label>
          <pui-radio-description>One-tap payment</pui-radio-description>
        </pui-radio>
      </pui-radio-group>
    `,
