{
  globalTypes: {
    theme: {
      description: 'Theme',
      defaultValue: 'light',
      toolbar: {
        title: 'Theme',
        icon: 'circlehollow',
        items: [
          { value: 'light', title: 'Light' },
          { value: 'dark', title: 'Dark' }
        ],
        dynamicTitle: true
      }
    }
  },
  decorators: [
    (story, context) => {
      const theme =
        context.globals['theme'] === 'dark'
          ? 'dark'
          : 'light';
  
      const storyResult = story();
  
      return {
        ...storyResult,
  
        template: `
          <div
            data-theme="${theme}"
            style="
              min-height: 100vh;
              padding: 2rem;
              background: var(--pui-color-background);
              color: var(--pui-color-text);
            "
          >
            ${storyResult.template}
          </div>
        `,
  
        props: storyResult.props
      };
    }
  ],
  parameters: {
    backgrounds: {
      disable: true
    },
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i
      }
    },
    a11y: {
      test: 'error'
    },
    options: {
      storySort: {
        order: ['Introduction', 'Foundations', ['Colors', 'Typography', 'Spacing', 'Shadows'], 'Components', 'Forms', 'Feedback', 'Navigation', 'Overlays']
      }
    }
  }
}

